import { useState } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NetworkRequest } from './networkRequest';

const DebuggingModule = () => {
  const [logs, setLogs] = useState([]);

  // Capture network requests
  const handleNetworkRequest = (request) => {
    console.log('Network request:', request);
    setLogs((prevLogs) => [...prevLogs, { type: 'network-request', data: request }]);
  };

  // Capture AsyncStorage operations
  const handleAsyncStorageOperation = (operation) => {
    console.log('AsyncStorage operation:', operation);
    setLogs((prevLogs) => [...prevLogs, { type: 'async-storage-operation', data: operation }]);
  };

  // Capture user actions
  const handleUserAction = (action) => {
    console.log('User action:', action);
    setLogs((prevLogs) => [...prevLogs, { type: 'user-action', data: action }]);
  };

  // Capture state changes
  const handleStateChange = (state) => {
    console.log('State change:', state);
    setLogs((prevLogs) => [...prevLogs, { type: 'state-change', data: state }]);
  };

  // Capture authentication tokens
  const handleAuthenticationToken = (token) => {
    console.log('Authentication token:', token);
    setLogs((prevLogs) => [...prevLogs, { type: 'authentication-token', data: token }]);
  };

  // Capture user data
  const handleUserData = (data) => {
    console.log('User data:', data);
    setLogs((prevLogs) => [...prevLogs, { type: 'user-data', data: data }]);
  };

  // Capture API responses
  const handleAPIResponse = (response) => {
    console.log('API response:', response);
    setLogs((prevLogs) => [...prevLogs, { type: 'api-response', data: response }]);
  };

  // Set up network request listener
  NetworkRequest.addListener(handleNetworkRequest);

  // Set up AsyncStorage operation listener
  AsyncStorage.addListener(handleAsyncStorageOperation);

  // Set up user action listener
  UserAction.addListener(handleUserAction);

  // Set up state change listener
  StateChange.addListener(handleStateChange);

  // Set up authentication token listener
  AuthenticationToken.addListener(handleAuthenticationToken);

  // Set up user data listener
  UserData.addListener(handleUserData);

  // Set up API response listener
  APIResponse.addListener(handleAPIResponse);

  return (
    <View>
      {logs.map((log) => (
        <Text key={log.id}>{log.type}: {JSON.stringify(log.data)}</Text>
      ))}
    </View>
  );
};